import json


def lambda_handler(event, context):
    """
    AWS Lambda function that serves user data as JSON for a single-page application.
    Configured with permissive CORS headers for development flexibility.
    """
    
    # Define CORS headers to allow requests from any origin
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, X-Api-Key",
        "Access-Control-Max-Age": "86400",
        "Content-Type": "application/json"
    }
    
    # Extract HTTP method from the event
    http_method = event.get("httpMethod", "GET")
    
    # Handle CORS preflight OPTIONS request
    if http_method == "OPTIONS":
        return {
            "statusCode": 200,
            "headers": cors_headers,
            "body": json.dumps({"message": "CORS preflight response"})
        }
    
    # Extract path and query parameters
    path_parameters = event.get("pathParameters") or {}
    query_parameters = event.get("queryStringParameters") or {}
    
    try:
        # Route based on HTTP method and path
        if http_method == "GET":
            user_id = path_parameters.get("userId") or query_parameters.get("userId")
            
            if user_id:
                # Return a specific user
                user_data = _get_user_by_id(user_id)
                if user_data:
                    return {
                        "statusCode": 200,
                        "headers": cors_headers,
                        "body": json.dumps({"success": True, "data": user_data})
                    }
                else:
                    return {
                        "statusCode": 404,
                        "headers": cors_headers,
                        "body": json.dumps({
                            "success": False,
                            "error": "User not found",
                            "userId": user_id
                        })
                    }
            else:
                # Return all users
                users = _get_all_users()
                return {
                    "statusCode": 200,
                    "headers": cors_headers,
                    "body": json.dumps({
                        "success": True,
                        "data": users,
                        "count": len(users)
                    })
                }
        
        elif http_method == "POST":
            # Create a new user
            body = json.loads(event.get("body", "{}"))
            new_user = _create_user(body)
            return {
                "statusCode": 201,
                "headers": cors_headers,
                "body": json.dumps({"success": True, "data": new_user})
            }
        
        elif http_method == "PUT":
            # Update an existing user
            user_id = path_parameters.get("userId")
            body = json.loads(event.get("body", "{}"))
            updated_user = _update_user(user_id, body)
            if updated_user:
                return {
                    "statusCode": 200,
                    "headers": cors_headers,
                    "body": json.dumps({"success": True, "data": updated_user})
                }
            else:
                return {
                    "statusCode": 404,
                    "headers": cors_headers,
                    "body": json.dumps({
                        "success": False,
                        "error": "User not found"
                    })
                }
        
        elif http_method == "DELETE":
            user_id = path_parameters.get("userId")
            deleted = _delete_user(user_id)
            if deleted:
                return {
                    "statusCode": 200,
                    "headers": cors_headers,
                    "body": json.dumps({
                        "success": True,
                        "message": f"User {user_id} deleted"
                    })
                }
            else:
                return {
                    "statusCode": 404,
                    "headers": cors_headers,
                    "body": json.dumps({
                        "success": False,
                        "error": "User not found"
                    })
                }
        
        else:
            return {
                "statusCode": 405,
                "headers": cors_headers,
                "body": json.dumps({
                    "success": False,
                    "error": f"Method {http_method} not allowed"
                })
            }
    
    except json.JSONDecodeError:
        return {
            "statusCode": 400,
            "headers": cors_headers,
            "body": json.dumps({
                "success": False,
                "error": "Invalid JSON in request body"
            })
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "headers": cors_headers,
            "body": json.dumps({
                "success": False,
                "error": "Internal server error",
                "message": str(e)
            })
        }


