def _get_all_users():
    """Retrieve all users."""
    return list(_MOCK_USERS.values())


def _get_user_by_id(user_id):
    """Retrieve a single user by ID."""
    return _MOCK_USERS.get(str(user_id))


def _create_user(user_data):
    """Create a new user."""
    new_id = str(max(int(k) for k in _MOCK_USERS.keys()) + 1)
    new_user = {
        "id": new_id,
        "username": user_data.get("username", ""),
        "email": user_data.get("email", ""),
        "firstName": user_data.get("firstName", ""),
        "lastName": user_data.get("lastName", ""),
        "role": user_data.get("role", "viewer"),
        "active": user_data.get("active", True)
    }
    _MOCK_USERS[new_id] = new_user
    return new_user


def _update_user(user_id, user_data):
    """Update an existing user."""
    user_id = str(user_id)
    if user_id not in _MOCK_USERS:
        return None
    existing = _MOCK_USERS[user_id]
    for key in ["username", "email", "firstName", "lastName", "role", "active"]:
        if key in user_data:
            existing[key] = user_data[key]
    return existing


def _delete_user(user_id):
    """Delete a user by ID."""
    user_id = str(user_id)
    if user_id in _MOCK_USERS:
        del _MOCK_USERS[user_id]
        return True
    return False


